INSERT INTO `chatbot_responses` (`id`, `keyword`, `response`, `is_active`, `priority`, `match_type`, `created_at`, `updated_at`) VALUES
	(1, 'halo', 'Halo! Selamat datang di CSIRT Kalselprov. 😊\n\nSaya siap membantu Anda dengan:\n- Membuat tiket baru\n- Mengecek status tiket\n- Memberikan informasi\n\nKetik /help untuk bantuan lebih lanjut.', 1, 50, 'contains', '2026-02-27 14:42:52', '2026-02-27 14:42:52'),
	(2, 'hi', 'Hi! Selamat datang di CSIRT Kalselprov. 😊\n\nSaya siap membantu Anda. Ketik /help untuk melihat daftar perintah.', 1, 50, 'contains', '2026-02-27 14:42:52', '2026-02-27 14:42:52'),
	(3, 'selamat pagi', 'Selamat pagi! 🌅\n\nTerima kasih telah menghubungi CSIRT Kalselprov. Ada yang bisa saya bantu hari ini?\n\nKetik /help untuk melihat daftar perintah.', 1, 50, 'contains', '2026-02-27 14:42:52', '2026-02-27 14:42:52'),
	(4, 'selamat siang', 'Selamat siang! ☀️\n\nTerima kasih telah menghubungi CSIRT Kalselprov. Ada yang bisa saya bantu?\n\nKetik /help untuk melihat daftar perintah.', 1, 50, 'contains', '2026-02-27 14:42:52', '2026-02-27 14:42:52'),
	(5, 'selamat malam', 'Selamat malam! 🌙\n\nTerima kasih telah menghubungi CSIRT Kalselprov. Ada yang bisa saya bantu?\n\nKetik /help untuk melihat daftar perintah.', 1, 50, 'contains', '2026-02-27 14:42:52', '2026-02-27 14:42:52'),
	(6, '/start', '👋 *Selamat datang di CSIRT Kalselprov Bot!*\n\nSaya siap membantu Anda dengan:\n✅ Membuat tiket baru\n✅ Mengecek status tiket\n✅ Memberikan informasi\n\nKetik /help untuk melihat daftar perintah lengkap.\n\nSelamat menggunakan! 😊', 1, 100, 'exact', '2026-02-27 14:42:52', '2026-02-27 14:42:52'),
	(7, '/help', '📋 *Daftar Perintah:*\n\n/start - Memulai bot\n/help - Menampilkan bantuan ini\n/tiket - Membuat tiket baru\n/status - Cek status tiket\n/info - Informasi tentang CSIRT\n\n*Atau langsung ketik pertanyaan Anda!*\n\nContoh:\n- "cara buat tiket"\n- "info CSIRT"\n- "bantuan"', 1, 100, 'exact', '2026-02-27 14:42:52', '2026-02-27 14:42:52'),
	(8, '/info', 'ℹ️ *Informasi CSIRT Kalselprov*\n\nCSIRT (Computer Security Incident Response Team) Kalselprov adalah tim yang bertanggung jawab untuk menangani insiden keamanan siber di lingkungan pemerintah Kalimantan Selatan.\n\n*Layanan kami:*\n- Penanganan insiden keamanan siber\n- Laporan dan pelacakan tiket\n- Konsultasi keamanan informasi\n\nUntuk informasi lebih lanjut, kunjungi portal kami atau hubungi admin.', 1, 100, 'exact', '2026-02-27 14:42:52', '2026-02-27 14:42:52'),
	(9, 'cara buat tiket', '📝 *Cara Membuat Tiket:*\n\n1. Login ke portal CSIRT Kalselprov\n2. Klik menu "Buat Tiket Baru"\n3. Isi form dengan lengkap:\n   - Subject/Pokok permasalahan\n   - Deskripsi masalah secara detail\n   - Priority (Low, Medium, High, Critical)\n   - Kategori/Departemen\n4. Klik Submit untuk mengirim tiket\n\nAtau hubungi admin untuk bantuan lebih lanjut.\n\nKetik /help untuk perintah lainnya.', 1, 80, 'contains', '2026-02-27 14:42:52', '2026-02-27 14:42:52'),
	(10, 'buat tiket', 'Untuk membuat tiket baru:\n\n1. Login ke portal CSIRT\n2. Klik "Buat Tiket Baru"\n3. Isi form dengan lengkap\n4. Submit tiket\n\nAtau ketik "cara buat tiket" untuk panduan lengkap.', 1, 70, 'contains', '2026-02-27 14:42:52', '2026-02-27 14:42:52'),
	(11, 'tiket baru', 'Untuk membuat tiket baru, silakan login ke portal CSIRT dan klik menu "Buat Tiket Baru".\n\nKetik "cara buat tiket" untuk panduan lengkap.', 1, 70, 'contains', '2026-02-27 14:42:52', '2026-02-27 14:42:52'),
	(12, 'status tiket', '🔍 *Cek Status Tiket*\n\nUntuk mengecek status tiket Anda:\n\n1. Login ke portal CSIRT\n2. Masukkan nomor tiket Anda\n3. Lihat detail status dan update terbaru\n\nAtau hubungi admin jika mengalami kendala.\n\nKetik /help untuk perintah lainnya.', 1, 80, 'contains', '2026-02-27 14:42:52', '2026-02-27 14:42:52'),
	(13, 'cek status', 'Untuk mengecek status tiket, silakan login ke portal CSIRT dan masukkan nomor tiket Anda.\n\nKetik "status tiket" untuk informasi lebih lanjut.', 1, 70, 'contains', '2026-02-27 14:42:52', '2026-02-27 14:42:52'),
	(14, 'bantuan', '💬 Saya siap membantu Anda!\n\nAnda bisa menanyakan:\n- Cara membuat tiket\n- Status tiket Anda\n- Informasi tentang CSIRT\n- Dan lainnya\n\nKetik /help untuk melihat daftar perintah lengkap.\n\nAtau langsung ketik pertanyaan Anda!', 1, 60, 'contains', '2026-02-27 14:42:52', '2026-02-27 14:42:52'),
	(15, 'help', 'Saya siap membantu! Ketik /help untuk melihat daftar perintah lengkap.\n\nAtau ketik pertanyaan Anda langsung, seperti:\n- "cara buat tiket"\n- "status tiket"\n- "info"', 1, 60, 'contains', '2026-02-27 14:42:52', '2026-02-27 14:42:52'),
	(16, 'info', 'ℹ️ Informasi CSIRT Kalselprov:\n\nCSIRT adalah tim yang menangani insiden keamanan siber di lingkungan pemerintah Kalimantan Selatan.\n\n*Layanan:*\n- Penanganan insiden keamanan siber\n- Laporan dan pelacakan tiket\n- Konsultasi keamanan\n\nKetik /info untuk informasi lebih lengkap.', 1, 60, 'contains', '2026-02-27 14:42:52', '2026-02-27 14:42:52'),
	(17, 'tidak tahu', 'Maaf, saya tidak mengerti pertanyaan Anda. 😔\n\nSilakan coba salah satu dari:\n- Ketik /help untuk melihat daftar perintah\n- Ketik "cara buat tiket" untuk panduan\n- Ketik "bantuan" untuk bantuan\n- Hubungi admin untuk bantuan lebih lanjut\n\nTerima kasih!', 1, 10, 'contains', '2026-02-27 14:42:52', '2026-02-27 14:42:52'),
	(18, 'tidak mengerti', 'Maaf, saya belum memahami pertanyaan Anda. 😔\n\nSilakan ketik /help untuk melihat daftar perintah yang tersedia.\n\nAtau coba format pertanyaan Anda dengan lebih spesifik, seperti:\n- "cara buat tiket"\n- "info CSIRT"\n- "status tiket"', 1, 10, 'contains', '2026-02-27 14:42:52', '2026-02-27 14:42:52');
