INSERT INTO `respons_template` (`id`, `title`, `body`, `created_at`, `updated_at`) VALUES
	(1, 'Laporan Diterima', 'Terima kasih telah melaporkan insiden keamanan siber. Tim CSIRT akan segera meninjau laporan Anda dan memberikan respons sesuai dengan SLA yang berlaku.', '2026-02-27 14:42:48', '2026-02-27 14:42:48'),
	(2, 'Masalah Sedang Ditangani', 'Laporan Anda sedang ditangani oleh tim teknis kami. Kami akan memberikan update segera setelah ada perkembangan.', '2026-02-27 14:42:48', '2026-02-27 14:42:48'),
	(3, 'Memerlukan Informasi Tambahan', 'Untuk menangani laporan Anda dengan lebih baik, kami memerlukan informasi tambahan. Mohon kirimkan detail berikut:', '2026-02-27 14:42:48', '2026-02-27 14:42:48'),
	(4, 'Laporan Diselesaikan', 'Laporan insiden siber Anda telah diselesaikan. Jika Anda memiliki pertanyaan lebih lanjut, silakan balas email ini atau buat laporan baru.', '2026-02-27 14:42:48', '2026-02-27 14:42:48'),
	(5, 'Penanganan Insiden Ransomware', 'Terima kasih telah melaporkan insiden ransomware. Tim keamanan siber kami telah mengisolasi sistem yang terinfeksi. Langkah-langkah pencegahan telah diterapkan untuk mencegah penyebaran lebih lanjut.', '2026-02-27 14:42:48', '2026-02-27 14:42:48'),
	(6, 'Penanganan Phishing', 'Terima kasih telah melaporkan email phishing. Email tersebut telah diblokir dan semua pengguna telah diberi peringatan. Mohon untuk tidak membuka link atau attachment dari email yang mencurigakan.', '2026-02-27 14:42:48', '2026-02-27 14:42:48');
