INSERT INTO `utas_tiket` (`id`, `ticket_id`, `type`, `user_id`, `body`, `created_at`, `updated_at`) VALUES
	(1, 1, 'message', NULL, 'Saya menemukan serangan ransomware pada server utama. File-file penting sudah terenkripsi. Mohon segera ditangani.', '2026-02-27 14:42:51', '2026-02-27 14:42:51'),
	(2, 2, 'message', NULL, 'Ada email phishing yang masuk ke semua user di organisasi. Email tersebut meminta login credentials.', '2026-02-27 14:42:51', '2026-02-27 14:42:51'),
	(3, 3, 'message', NULL, 'Terjadi kebocoran data pribadi pegawai. Data seperti nama, email, dan nomor telepon terlihat di publik.', '2026-02-27 14:42:51', '2026-02-27 14:42:51'),
	(4, 4, 'message', NULL, 'Saya menemukan vulnerability pada sistem aplikasi yang bisa dieksploitasi oleh attacker.', '2026-02-27 14:42:51', '2026-02-27 14:42:51'),
	(5, 5, 'message', NULL, 'Server database tiba-tiba down dan tidak bisa diakses. Aplikasi tidak bisa berfungsi normal.', '2026-02-27 14:42:51', '2026-02-27 14:42:51'),
	(6, 6, 'message', NULL, 'Network di gedung A sangat lambat. Banyak user yang mengeluhkan koneksi internet.', '2026-02-27 14:42:51', '2026-02-27 14:42:51'),
	(7, 6, 'reply', 5, 'Network issue telah diperbaiki. Router telah di-restart dan koneksi sudah kembali normal.', '2026-02-27 14:42:51', '2026-02-27 14:42:51'),
	(8, 7, 'message', NULL, 'Aplikasi login error, tidak bisa masuk meskipun password sudah benar.', '2026-02-27 14:42:51', '2026-02-27 14:42:51'),
	(9, 7, 'reply', 2, 'Masalah login telah diperbaiki. Silakan coba login lagi.', '2026-02-27 14:42:51', '2026-02-27 14:42:51'),
	(10, 8, 'message', NULL, 'Firewall memblokir traffic yang legitimate. Beberapa layanan tidak bisa diakses.', '2026-02-27 14:42:51', '2026-02-27 14:42:51'),
	(11, 8, 'reply', 2, 'Firewall rules telah diperbarui. Traffic legitimate sekarang bisa lewat dengan normal.', '2026-02-27 14:42:51', '2026-02-27 14:42:51'),
	(12, 9, 'message', NULL, 'Email server tidak bisa mengirim email. Semua email yang dikirim gagal.', '2026-02-27 14:42:51', '2026-02-27 14:42:51'),
	(13, 9, 'reply', 1, 'Email server telah diperbaiki. Masalah terjadi pada konfigurasi SMTP yang sudah diperbaiki.', '2026-02-27 14:42:51', '2026-02-27 14:42:51'),
	(14, 10, 'message', NULL, 'VPN connection sering putus. User kesulitan untuk remote access.', '2026-02-27 14:42:51', '2026-02-27 14:42:51'),
	(15, 10, 'reply', 5, 'VPN connection issue telah diselesaikan. Server VPN telah di-restart.', '2026-02-27 14:42:51', '2026-02-27 14:42:51'),
	(16, 11, 'message', NULL, 'Malware terdeteksi pada PC staf. Antivirus sudah menghapus tapi perlu pengecekan lebih lanjut.', '2026-02-27 14:42:51', '2026-02-27 14:42:51'),
	(17, 11, 'reply', 5, 'PC yang terinfeksi telah diisolasi dan di-clean. Scan mendalam telah dilakukan.', '2026-02-27 14:42:51', '2026-02-27 14:42:51'),
	(18, 12, 'message', NULL, 'Ada aktivitas mencurigakan di network. Traffic aneh dari beberapa IP address.', '2026-02-27 14:42:51', '2026-02-27 14:42:51'),
	(19, 12, 'reply', 1, 'Aktivitas mencurigakan sedang diselidiki. IP yang mencurigakan telah diblokir.', '2026-02-27 14:42:51', '2026-02-27 14:42:51'),
	(20, 13, 'message', NULL, 'Data backup gagal. Backup otomatis tidak berjalan dengan baik.', '2026-02-27 14:42:51', '2026-02-27 14:42:51'),
	(21, 13, 'reply', 3, 'Backup system telah diperbaiki. Backup otomatis sekarang berjalan normal.', '2026-02-27 14:42:51', '2026-02-27 14:42:51'),
	(22, 13, 'reply', 3, 'Laporan insiden siber telah diselesaikan. Jika ada pertanyaan lebih lanjut, silakan buat laporan baru.', '2026-02-27 14:42:51', '2026-02-27 14:42:51'),
	(23, 14, 'message', NULL, 'Aplikasi E-Government error. User tidak bisa mengakses beberapa fitur.', '2026-02-27 14:42:52', '2026-02-27 14:42:52'),
	(24, 14, 'reply', 5, 'Aplikasi E-Government telah di-update. Error sudah diperbaiki.', '2026-02-27 14:42:52', '2026-02-27 14:42:52'),
	(25, 14, 'reply', 5, 'Laporan insiden siber telah diselesaikan. Jika ada pertanyaan lebih lanjut, silakan buat laporan baru.', '2026-02-27 14:42:52', '2026-02-27 14:42:52'),
	(26, 15, 'message', NULL, 'Printer network tidak bisa diakses. Semua PC tidak bisa print ke printer tersebut.', '2026-02-27 14:42:52', '2026-02-27 14:42:52'),
	(27, 15, 'reply', 2, 'Printer network telah di-reset. Sekarang sudah bisa diakses dari semua PC.', '2026-02-27 14:42:52', '2026-02-27 14:42:52'),
	(28, 15, 'reply', 2, 'Laporan insiden siber telah diselesaikan. Jika ada pertanyaan lebih lanjut, silakan buat laporan baru.', '2026-02-27 14:42:52', '2026-02-27 14:42:52'),
	(29, 13, 'reply', 1, 'Laporan insiden siber Anda telah diselesaikan. Jika Anda memiliki pertanyaan lebih lanjut, silakan balas email ini atau buat laporan baru.', '2026-04-23 16:38:02', '2026-04-23 16:38:02'),
	(30, 14, 'reply', 1, 'Laporan insiden siber Anda telah diselesaikan. Jika Anda memiliki pertanyaan lebih lanjut, silakan balas email ini atau buat laporan baru.', '2026-04-23 16:38:57', '2026-04-23 16:38:57'),
	(31, 5, 'reply', 1, 'Laporan Anda sedang ditangani oleh tim teknis kami. Kami akan memberikan update segera setelah ada perkembangan.', '2026-04-23 17:18:56', '2026-04-23 17:18:56'),
	(32, 5, 'reply', 1, 'Terima kasih telah melaporkan insiden keamanan siber. Tim CSIRT akan segera meninjau laporan Anda dan memberikan respons sesuai dengan SLA yang berlaku.', '2026-04-23 17:19:25', '2026-04-23 17:19:25'),
	(33, 5, 'note', 1, 'ini penting', '2026-04-23 17:20:01', '2026-04-23 17:20:01'),
	(34, 3, 'reply', 1, 'Laporan insiden siber Anda telah diselesaikan. Jika Anda memiliki pertanyaan lebih lanjut, silakan balas email ini atau buat laporan baru.', '2026-04-24 01:03:29', '2026-04-24 01:03:29');
